/**
 * Format 1 bloc — à placer dans la Loop (Split in Batches = 1)
 * Entrée : { top, childrenMap, dest_id, root }
 * Sortie : [{
 *   dest_id,
 *   children_payload: { children: [ formattedWithChildren ] },
 *   debug: {...}
 * }]
 */

const original = $json.top;
const childrenMap = $json.childrenMap || {};
const destId = $json.dest_id;
const rootInfo = $json.root || null;

function detectType(block) {
  if (typeof block?.type === 'string' && block[block.type]) return block.type;
  const KNOWN = ['paragraph','heading_1','heading_2','heading_3','bulleted_list_item','numbered_list_item','to_do','toggle','quote','code','callout','divider','table_of_contents','link_to_page','synced_block','bookmark','image','video','pdf','file','column_list','column','table','table_row','equation'];
  for (const k of KNOWN) if (block && block[k]) return k;
  if (block?.unsupported) return 'unsupported';
  return null;
}

function rt(node) {
  if (!node) return [{ type:'text', text:{ content:'' }, annotations:{ bold:false, italic:false, strikethrough:false, underline:false, code:false, color:'default' }, plain_text:'', href:null }];
  if (Array.isArray(node.text)) return node.text;
  if (Array.isArray(node.rich_text)) return node.rich_text;
  return [{ type:'text', text:{ content:'' }, annotations:{ bold:false, italic:false, strikethrough:false, underline:false, code:false, color:'default' }, plain_text:'', href:null }];
}

function getChildrenOf(id) {
  const arr = childrenMap[id];
  return Array.isArray(arr) ? arr : [];
}

function formatOne(b) {
  const t = detectType(b) || 'paragraph';
  let out = { object:'block', type:t };

  switch (t) {
    case 'paragraph':
      out.paragraph = { rich_text: rt(b.paragraph), color: b.paragraph?.color || 'default' };
      break;
    case 'heading_1':
      out.heading_1 = { rich_text: rt(b.heading_1), color: b.heading_1?.color || 'default', is_toggleable: false };
      break;
    case 'heading_2':
      out.heading_2 = { rich_text: rt(b.heading_2), color: b.heading_2?.color || 'default', is_toggleable: false };
      break;
    case 'heading_3':
      out.heading_3 = { rich_text: rt(b.heading_3), color: b.heading_3?.color || 'default', is_toggleable: false };
      break;
    case 'bulleted_list_item':
      out.bulleted_list_item = { rich_text: rt(b.bulleted_list_item), color: b.bulleted_list_item?.color || 'default' };
      break;
    case 'numbered_list_item':
      out.numbered_list_item = { rich_text: rt(b.numbered_list_item), color: b.numbered_list_item?.color || 'default' };
      break;
    case 'to_do':
      out.to_do = { rich_text: rt(b.to_do), checked: b.to_do?.checked || false, color: b.to_do?.color || 'default' };
      break;
    case 'quote':
      out.quote = { rich_text: rt(b.quote), color: b.quote?.color || 'default' };
      break;
    case 'code':
      out.code = { rich_text: rt(b.code), language: b.code?.language || 'plain text', caption: Array.isArray(b.code?.caption)? b.code.caption : [] };
      break;
    case 'divider':
      out.divider = {}; break;
    case 'callout':
      out.callout = { rich_text: rt(b.callout), icon: b.callout?.icon ?? { emoji:'💡' }, color: b.callout?.color || 'default' };
      break;
    case 'toggle':
      out.toggle = { rich_text: rt(b.toggle), color: b.toggle?.color || 'default' };
      break;
    default:
      out.type = 'paragraph';
      out.paragraph = { rich_text: [{ type:'text', text:{ content:'[Bloc converti]' }, annotations:{ bold:false, italic:false, strikethrough:false, underline:false, code:false, color:'default' }, plain_text:'[Bloc converti]', href:null }], color: 'default' };
      break;
  }

  const kids = getChildrenOf(b.id);
  if (kids.length > 0) {
    out.children = kids.map(ch => formatOne(ch));
    if (t === 'heading_1' && out.heading_1) out.heading_1.is_toggleable = true;
    if (t === 'heading_2' && out.heading_2) out.heading_2.is_toggleable = true;
    if (t === 'heading_3' && out.heading_3) out.heading_3.is_toggleable = true;
  }
  return out;
}

const formatted = formatOne(original);
const payload = { children: [ formatted ] };

return [{
  json: {
    dest_id: destId,
    children_payload: payload,
    debug: {
      root: rootInfo,
      source_block_id: original.id,
      children_count: (childrenMap[original.id]?.length || 0)
    }
  }

}];

/**
 * Index Children — MULTI-PAGE
 * - Construit childrenMap (parent_block_id -> [children])
 * - Détecte TOUTES les pages sources présentes dans l'input
 * - Émet un item par bloc top-level POUR CHAQUE page
 * - Supporte un mapping optionnel source_page_id -> dest_id
 *
 * Entrée: items (top-level + sous-blocs) de plusieurs pages possibles
 * Sortie: [{ json: { top, childrenMap, dest_id, root:{type:'page', id:'...'} } }, ...]
 */

function normId(s){ return (s||'').toString().replace(/-/g,'').toLowerCase(); }

// 1) Tous les blocs
const all = $input.all().map(i => i.json);

// 2) Destination par défaut (optionnelle)
let defaultDestId;
try { defaultDestId = $('Set Destination').first().json.destination_id; } catch (e) {}
if (!defaultDestId) { try { defaultDestId = $('Create Contrôle Certificat').first().json.id; } catch (e) {} }

// 3) Mapping source_page_id -> dest_id (OPTIONNEL)
//   Crée un node "Set Destinations" en amont qui renvoie plusieurs lignes {source_page_id, dest_id}
const destMap = {};
try {
  const rows = $('Set Destinations').all().map(n => n.json);
  for (const r of rows) {
    if (r?.source_page_id && r?.dest_id) destMap[normId(r.source_page_id)] = String(r.dest_id);
  }
} catch (e) { /* mapping absent = OK */ }

// 4) Roots explicites ? (si tu gardes un “Set Root”, on ne traite QUE celle-ci)
let explicitRoot = null;
try {
  const r = $('Set Root').first().json;
  if (r?.root_id) explicitRoot = { type: String(r.root_type || 'page'), id: String(r.root_id) };
} catch (e) {}

// 5) Construire childrenMap global (OK multi-pages, ids Notion sont uniques)
const childrenMap = {}; // { [blockId]: Block[] }
for (const b of all) {
  if (b?.parent?.type === 'block_id' && b.parent.block_id) {
    const pid = b.parent.block_id;
    if (!childrenMap[pid]) childrenMap[pid] = [];
    childrenMap[pid].push(b);
  }
}

// 6) Lister les pages présentes dans l'input
const pagesSeen = new Map(); // normPageId -> rawPageId
for (const b of all) {
  if (b?.parent?.type === 'page_id' && b.parent.page_id) {
    const nid = normId(b.parent.page_id);
    if (!pagesSeen.has(nid)) pagesSeen.set(nid, b.parent.page_id);
  }
}

// 7) Déterminer les roots à traiter
let roots = [];
if (explicitRoot?.type === 'page' && explicitRoot.id) {
  roots = [ explicitRoot ];
} else {
  // traite TOUTES les pages rencontrées
  roots = [...pagesSeen.entries()].map(([nid, raw]) => ({ type: 'page', id: raw }));
  // fallback : s’il n’y a aucune page vue (rare), tente une heuristique
  if (roots.length === 0) {
    const firstTop = all.find(x => x?.parent?.type==='page_id' && x.parent.page_id);
    if (firstTop) roots = [{ type:'page', id:firstTop.parent.page_id }];
  }
}

// 8) Construire la sortie : tous les top-level de chaque page, avec dest_id dédié
const out = [];
for (const root of roots) {
  const rid = normId(root.id);
  const topLevel = all.filter(b => b?.parent?.type === 'page_id' && normId(b.parent.page_id) === rid);

  // destination pour CETTE page : mapping > défaut > undefined (on laisse HTTP échouer proprement si vide)
  const destForThisPage = destMap[rid] || defaultDestId || undefined;

  for (const b of topLevel) {
    out.push({
      json: { top: b, childrenMap, dest_id: destForThisPage, root }
    });
  }
}

return out;

/**
 * Build Cascade Queue — retire `children` du parent et seed la file
 */
const destId = $json.dest_id;
const parent = ($json.children_payload?.children || [])[0];

if (!destId || !parent) {
  return [{ json: { error: 'missing_dest_or_parent' } }];
}

// strip children au parent
const kids = Array.isArray(parent.children) ? parent.children : [];
const parentNoKids = { ...parent };
delete parentNoKids.children;

// initialise la file avec 1 tâche "créer le parent sous destId"
const queue = [{
  parentId: destId,
  block: parentNoKids,
  children: kids
}];

return [{ json: { queue } }];

/**
 * Pop Task — sort la prochaine tâche de la file
 */
const q = Array.isArray($json.queue) ? $json.queue : [];
if (q.length === 0) {
  return [{ json: { done: true, queue: [] } }];
}

const task = q.shift();
return [{
  json: {
    done: false,
    queue: q,                     // ← gardé pour Merge/After
    parentId: task.parentId,      // ← utilisé par HTTP URL
    block: task.block,            // ← utilisé par HTTP body (sans children !)
    children: task.children || [] // ← gardé pour After Append
  }
}];

/**
 * After Append — version "après Merge (Pass Through)"
 * Entrée (depuis Merge):
 *  - champs de Pop Task: queue[], children[], parentId, block
 *  - réponse HTTP Notion: results[0].id, etc.
 * Sortie:
 *  - { queue: [...prochaines tâches...] }
 */

// 1) Lire la réponse Notion (côté HTTP)
const resp = $json; // Merge a copié la réponse HTTP dans le même objet
const results = resp.results || resp.data?.results || [];
const newId = results[0]?.id;

// 2) Lire la file et les enfants venant de Pop Task (conservés par le Merge)
let q = Array.isArray($json.queue) ? $json.queue : [];
const kids = Array.isArray($json.children) ? $json.children : [];

// 3) Si l'API n'a pas renvoyé d'ID, on log et on continue (ou tu peux throw si tu veux stopper)
if (!newId) {
  return [{
    json: { error: 'append_failed_no_id', queue: q, debug: { resp_has_results: results.length } }
  }];
}

// 4) Chaque enfant devient une tâche sous newId (strip de ses propres children)
function strip(b) {
  const copy = { ...b };
  const k = Array.isArray(b.children) ? b.children : [];
  delete copy.children;
  return { copy, k };
}

for (const child of kids) {
  const { copy, k } = strip(child);
  q.push({ parentId: newId, block: copy, children: k });
}

// 5) Retourner la nouvelle queue
return [{ json: { queue: q } }];

